/*
    SQL ID : AsmtDAO.mrkRfltrtModify
    설  명 : 성적반영비율 수정
*/
UPDATE TB_LMS_ASMT
SET MRK_RFLTRT = #{mrkRfltrt}
    , MDFR_ID = #{mdfrId}
    , MOD_DTTM = FN_DTTM()
WHERE ASMT_ID = #{asmtId}

/*
    SQL ID : AsmtDAO.mrkOynModify
    설  명 : 성적공개여부 수정
*/
UPDATE TB_LMS_ASMT
SET MRK_OYN = #{mrkOyn}
    , MDFR_ID = #{mdfrId}
    , MOD_DTTM = FN_DTTM()
WHERE ASMT_ID = #{asmtId}

