INSERT INTO TB_LMS_ASMT_GRP
(
      ASMT_GRP_ID
    , ASMT_GRPNM
    , RGTR_ID
    , REG_DTTM
)
VALUES
(
      #{asmtGrpId}
    , #{asmtGrpId}
    , #{rgtrId}
    , FN_DTTM()
)

/*
    SQL ID : AsmtDAO.asmtTrgtListRegist
    설  명 : 과제 대상 목록 등록
*/
