    INTO TB_LMS_ASMT_SBMSN_TRGT
    (
          ASMT_SBMSN_TRGT_ID
        , ASMT_ID
        , USER_ID
        , TEAM_ID
        , RGTR_ID
        , REG_DTTM
    )
    VALUES
    (
          #{item.asmtSbmsnTrgtId}
        , #{item.asmtId}
        , #{item.userId}
        , #{item.teamId}
        , #{item.rgtrId}
        , FN_DTTM()
    )

